import Foundation

let rawScores: [Int?] = [85, nil, 42, 91, nil, 73]

func processScores(_ scores: [Int?]) -> [String] {
    return scores
        .compactMap { $0 }
        .filter { $0 > 60 }
        .map { "\($0) Pass" }
}

let results = processScores(rawScores)
print(results.joined(separator: ", "))

