sections.solution:
import Foundation

let deposits = [100, 250, 75, 300]

func runningBalance(from amounts: [Int]) -> [Int] {
    var running = 0
    return amounts.map { amount in
        running += amount
        return running
    }
}

let balances = runningBalance(from: deposits)
print(balances.map(String.init).joined(separator: ", "))
